import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { BAKED_SDK_VERSIONS } from "./bakedSdkVersions.js";
import { checkForSdkUpdatesOffline, getBakedSdkVersion, isSdkVersionNewer, } from "./sdkUpdates.js";
describe("isSdkVersionNewer", () => {
    it("returns true when latest is strictly newer", () => {
        expect(isSdkVersionNewer("0.11.0", "0.10.0")).toBe(true);
        expect(isSdkVersionNewer("1.0.0", "0.11.9")).toBe(true);
        expect(isSdkVersionNewer("0.10.1", "0.10.0")).toBe(true);
    });
    it("returns false for equal versions", () => {
        expect(isSdkVersionNewer("0.11.0", "0.11.0")).toBe(false);
    });
    it("returns false when latest is older", () => {
        expect(isSdkVersionNewer("0.10.0", "0.11.0")).toBe(false);
    });
    it("returns false when current is null", () => {
        expect(isSdkVersionNewer("0.11.0", null)).toBe(false);
    });
    it("returns false on malformed versions", () => {
        expect(isSdkVersionNewer("not-a-version", "0.10.0")).toBe(false);
    });
    it("treats stable as newer than equivalent pre-release", () => {
        // User is on a beta; stable ships → should be considered newer.
        expect(isSdkVersionNewer("0.11.0", "0.11.0-beta.1")).toBe(true);
        expect(isSdkVersionNewer("0.11.0", "0.11.0-rc.2")).toBe(true);
        // Build metadata on latest shouldn't flip it.
        expect(isSdkVersionNewer("0.11.0+build.5", "0.11.0-beta.1")).toBe(true);
    });
    it("does not flip stable → pre-release as 'newer'", () => {
        expect(isSdkVersionNewer("0.11.0-rc.1", "0.11.0")).toBe(false);
    });
    it("compares numeric parts of pre-releases independently of the tag", () => {
        // Different major/minor/patch: still wins based on numbers.
        expect(isSdkVersionNewer("0.12.0-beta.1", "0.11.0-beta.9")).toBe(true);
        expect(isSdkVersionNewer("0.11.0-alpha.1", "0.12.0")).toBe(false);
    });
});
describe("getBakedSdkVersion", () => {
    it("returns non-empty versions for every language", () => {
        for (const lang of ["typescript", "python", "ruby", "go"]) {
            const v = getBakedSdkVersion(lang);
            expect(v).toMatch(/^\d+\.\d+\.\d+/);
            expect(v).toBe(BAKED_SDK_VERSIONS[lang]);
        }
    });
});
describe("checkForSdkUpdatesOffline", () => {
    let tmpDir;
    beforeEach(() => {
        tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-offline-"));
    });
    afterEach(() => {
        fs.rmSync(tmpDir, { recursive: true, force: true });
    });
    function write(relativePath, content) {
        const full = path.join(tmpDir, relativePath);
        fs.mkdirSync(path.dirname(full), { recursive: true });
        fs.writeFileSync(full, content);
    }
    it("returns empty when no SDK is present", () => {
        expect(checkForSdkUpdatesOffline(tmpDir)).toEqual([]);
    });
    it("marks outdated when resolved version trails baked version", () => {
        write("package.json", JSON.stringify({ dependencies: { bitfab: "^0.1.0" } }));
        write("pnpm-lock.yaml", `packages:\n  bitfab@0.1.0:\n    resolution: {integrity: sha512-x}\n`);
        const [status] = checkForSdkUpdatesOffline(tmpDir);
        expect(status.latestSource).toBe("baked");
        expect(status.remoteCheckFailed).toBe(false);
        expect(status.latest).toBe(BAKED_SDK_VERSIONS.typescript);
        expect(status.updateAvailable).toBe(true);
        expect(status.workspacePath).toBe(".");
    });
    it("marks up-to-date when resolved version matches baked version", () => {
        write("package.json", JSON.stringify({ dependencies: { bitfab: "*" } }));
        write("pnpm-lock.yaml", `packages:\n  bitfab@${BAKED_SDK_VERSIONS.typescript}:\n    resolution: {integrity: sha512-x}\n`);
        const [status] = checkForSdkUpdatesOffline(tmpDir);
        expect(status.updateAvailable).toBe(false);
    });
});
